// 모든 쿼리 결과 통합 및 LLM 프롬프트 구성 (Phase 5 강화)
const stats    = $('이상 유형별 통계').all().map(i => i.json);
const top5     = $('Top5 시스템 조회').all().map(i => i.json);
const critical = $('미처리 Critical 조회').first().json;
const metricAlerts = $('메트릭 이상 집계 조회').all().map(i => i.json);
const predictions  = $('장애 예측 항목 조회').all().map(i => i.json);

const today = new Date().toLocaleDateString('ko-KR', { timeZone: 'Asia/Seoul' });

// 로그 이상 유형별 집계
const typeSummary = {};
stats.forEach(r => {
  typeSummary[r.anomaly_type] = (typeSummary[r.anomaly_type] || 0) + parseInt(r.cnt, 10);
});
const totalLogAlerts = Object.values(typeSummary).reduce((a, b) => a + b, 0);

const statsText = [
  `신규(new): ${typeSummary.new || 0}건`,
  `반복(recurring): ${typeSummary.recurring || 0}건`,
  `유사(related): ${typeSummary.related || 0}건`,
  `중복(duplicate): ${typeSummary.duplicate || 0}건`
].join(', ');

const top5Text = top5.map((r, i) =>
  `${i + 1}. ${r.display_name}(${r.system_name}): ${r.cnt}건`
).join('\n');

// 메트릭 이상 요약
const metricText = metricAlerts.length
  ? metricAlerts.map(r =>
      `  - ${r.display_name}: ${r.collector_type}/${r.metric_group} [${r.llm_severity}]`
    ).join('\n')
  : '  없음';

// 장애 예측 요약
const predText = predictions.length
  ? predictions.map(r =>
      `  - ${r.display_name} (${r.collector_type}/${r.metric_group}): ${r.llm_prediction}`
    ).join('\n')
  : '  없음';

const prompt = `오늘(${today}) AOMS 모니터링 일일 리포트를 작성해 주세요.

[로그 이상 탐지 통계]
- 총 알림: ${totalLogAlerts}건
- ${statsText}

[주요 발생 시스템 Top 5]
${top5Text || '없음'}

[메트릭 이상 시스템]
${metricText}

[향후 12시간 내 장애 예측]
${predText}

[미처리 Critical]: ${critical.unresolved_critical || 0}건

3~4문장으로 오늘의 핵심 요약, 가장 주의가 필요한 시스템, 예방 조치 권고를 작성해 주세요. 한국어로 답변하세요.`;

return [{
  json: {
    prompt, today, totalLogAlerts, typeSummary, top5,
    metricAlerts, predictions,
    unresolvedCritical: critical.unresolved_critical || 0
  }
}];

const llmResp = $input.first().json;
const data    = $('리포트 데이터 통합').first().json;
const llmText = llmResp?.choices?.[0]?.message?.content 
  || llmResp?.response 
  || llmResp?.content 
  || '요약 생성 실패';

const today = data.today;
const ts    = data.typeSummary;
const top5  = data.top5 || [];
const metricAlerts = data.metricAlerts || [];
const predictions  = data.predictions || [];

const facts = [
  { title: '🆕 신규',  value: `${ts.new       || 0}건` },
  { title: '🔁 반복',  value: `${ts.recurring || 0}건` },
  { title: '🔗 유사',  value: `${ts.related   || 0}건` },
  { title: '🔄 중복',  value: `${ts.duplicate || 0}건` },
  { title: '⚠️ 미처리 Critical', value: `${data.unresolvedCritical}건` }
];

const top5Facts = top5.map((r, i) => ({
  title: `${i+1}위`,
  value: `${r.display_name}: ${r.cnt}건`
}));

const metricFacts = metricAlerts.slice(0, 5).map(r => ({
  title: r.display_name,
  value: `${r.collector_type}/${r.metric_group} [${r.llm_severity}]`
}));

const predFacts = predictions.slice(0, 3).map(r => ({
  title: r.display_name,
  value: r.llm_prediction?.substring(0, 60) || '-'
}));

const body = [
  { type: 'TextBlock', text: `📊 AOMS 일일 모니터링 리포트 (${today})`, weight: 'Bolder', size: 'Large' },
  { type: 'TextBlock', text: '로그 이상 분류 통계', weight: 'Bolder', size: 'Small', spacing: 'Medium' },
  { type: 'FactSet', facts },
  { type: 'TextBlock', text: '주요 발생 시스템 Top 5', weight: 'Bolder', size: 'Small', spacing: 'Medium' },
  { type: 'FactSet', facts: top5Facts.length ? top5Facts : [{ title: '-', value: '데이터 없음' }] }
];

if (metricFacts.length) {
  body.push({ type: 'TextBlock', text: '⚡ 메트릭 이상 시스템', weight: 'Bolder', size: 'Small', spacing: 'Medium' });
  body.push({ type: 'FactSet', facts: metricFacts });
}

if (predFacts.length) {
  body.push({ type: 'TextBlock', text: '🔮 향후 장애 예측', weight: 'Bolder', size: 'Small', spacing: 'Medium', color: 'Warning' });
  body.push({ type: 'FactSet', facts: predFacts });
}

body.push({ type: 'TextBlock', text: '🤖 AI 요약', weight: 'Bolder', size: 'Small', spacing: 'Medium' });
body.push({ type: 'TextBlock', text: llmText, wrap: true });

return [{
  json: {
    card: JSON.stringify({
      type: 'message',
      attachments: [{
        contentType: 'application/vnd.microsoft.card.adaptive',
        content: {
          '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
          type: 'AdaptiveCard',
          version: '1.4',
          body
        }
      }]
    }),
    llm_summary: llmText,
    system_count: top5.length
  }
}];
